algorithms.pseudocode:
FUNCTION ComputeLyapunovExponent(r0_traj, t_points, Θ0, H, γ, η, T, k):
    n ← dim(Θ0)
    D ← n*(n+1)/2 + n    // dimension of variational state (δΘ_upper, δr)

    // QR-based Lyapunov exponent computation
    // Initialize k orthonormal perturbation vectors
    Q ← random_orthonormal(D, k)  // D×k matrix
    lyap_sums ← zeros(k)
    n_renorm ← 0
    renorm_interval ← max(1, len(t_points) // 100)

    // Variational RHS: non-autonomous linear system
    FUNCTION variational_rhs(t, v, r0_t):
        // v = (δΘ_upper, δr) is a D-vector
        δΘ ← unflatten_symmetric(v[0:n*(n+1)/2])
        δr ← v[n*(n+1)/2:end]

        // d(δr_i)/dt = -η Σ_j Θ^{(0)}_{ij} δr_j - η Σ_j δΘ_{ij} · r_{0,j}(t)
        dδr_dt ← -η * Θ0 @ δr - η * δΘ @ r0_t

        // d(δΘ_{ij})/dt = -η Σ_k r_{0,k}(t) · H_{ijk}
        // Note: this is γ-dependent through the scaling of H
        dδΘ_dt ← -γ * einsum('ijk,k->ij', H, r0_t)
        // Actually: δΘ evolution also depends on δr for full coupling
        // d(δΘ_{ij})/dt = -(η/N) Σ_k [r_{0,k}(t) · δH_{ijk} + δr_k · H_{ijk}]
        // At leading order: d(δΘ_{ij})/dt = -(η/N) Σ_k δr_k · H_{ijk}
        dδΘ_dt ← -(γ) * einsum('ijk,k->ij', H, δr)

        RETURN concatenate(upper_triangle(dδΘ_dt), dδr_dt)

    // Integrate variational system with periodic QR reorthogonalization
    FOR step = 0 TO len(t_points)-2:
        dt ← t_points[step+1] - t_points[step]
        r0_t ← r0_traj[step]

        // Advance all k columns of Q by one time step (RK4)
        FOR col = 0 TO k-1:
            k1 ← variational_rhs(t_points[step], Q[:,col], r0_t)
            k2 ← variational_rhs(t_points[step]+dt/2, Q[:,col]+dt/2*k1, r0_t)
            k3 ← variational_rhs(t_points[step]+dt/2, Q[:,col]+dt/2*k2, r0_t)
            k4 ← variational_rhs(t_points[step]+dt, Q[:,col]+dt*k3, r0_t)
            Q[:,col] ← Q[:,col] + (dt/6)*(k1 + 2*k2 + 2*k3 + k4)

        // Periodic QR reorthogonalization to prevent numerical overflow
        IF (step+1) % renorm_interval == 0:
            Q, R ← qr_decomposition(Q)
            FOR i = 0 TO k-1:
                lyap_sums[i] += ln(abs(R[i,i]))
            n_renorm += 1

    // Final QR step
    Q, R ← qr_decomposition(Q)
    FOR i = 0 TO k-1:
        lyap_sums[i] += ln(abs(R[i,i]))
    n_renorm += 1

    // Compute Lyapunov exponents
    Λ_spectrum ← lyap_sums / T
    Λ_T ← Λ_spectrum[0]    // maximal Lyapunov exponent

    RETURN Λ_T, Λ_spectrum, Q[:,0]  // leading exponent, spectrum, leading vector
